// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 10000
#define MAX_M 20
#define MAX_P 80

// Structure to represent a piece of the cake
typedef struct {
    int x1, y1, x2, y2;
    int area;
} Piece;

// Function to calculate the area of a piece
int calculateArea(Piece piece) {
    return abs(piece.x2 - piece.x1) * abs(piece.y2 - piece.y1);
}

// Function to check if two pieces have a common side
int haveCommonSide(Piece piece1, Piece piece2) {
    // Check if the pieces have a common side
    if (piece1.x1 == piece2.x1 && piece1.x2 == piece2.x2 &&
        (piece1.y1 <= piece2.y1 && piece2.y1 <= piece1.y2 ||
         piece2.y1 <= piece1.y1 && piece1.y1 <= piece2.y2)) {
        return 1;
    }
    if (piece1.y1 == piece2.y1 && piece1.y2 == piece2.y2 &&
        (piece1.x1 <= piece2.x1 && piece2.x1 <= piece1.x2 ||
         piece2.x1 <= piece1.x1 && piece1.x1 <= piece2.x2)) {
        return 1;
    }
    return 0;
}

// Function to solve the problem
void solve() {
    int T, n, m, i, j, k;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &m);
        Piece pieces[MAX_P];
        int numPieces = 0;
        // Generate all possible pieces
        for (i = 0; i < n; i++) {
            for (j = 0; j < n; j++) {
                // Check if the current piece is not cut by any line
                int isValid = 1;
                for (k = 0; k < m; k++) {
                    int x1, y1, x2, y2;
                    scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
                    if (x1 == i && y1 == j && x2 == i && y2 == j) {
                        isValid = 0;
                        break;
                    }
                }
                if (isValid) {
                    Piece piece;
                    piece.x1 = i;
                    piece.y1 = j;
                    piece.x2 = i;
                    piece.y2 = j;
                    piece.area = calculateArea(piece);
                    pieces[numPieces++] = piece;
                }
            }
        }
        // Sort the pieces by their areas in descending order
        for (i = 0; i < numPieces; i++) {
            for (j = i + 1; j < numPieces; j++) {
                if (pieces[i].area < pieces[j].area) {
                    Piece temp = pieces[i];
                    pieces[i] = pieces[j];
                    pieces[j] = temp;
                }
            }
        }
        int maxArea = 0;
        // Choose the pieces that do not have a common side with any previously chosen piece
        for (i = 0; i < numPieces; i++) {
            int isValid = 1;
            for (j = 0; j < i; j++) {
                if (haveCommonSide(pieces[i], pieces[j])) {
                    isValid = 0;
                    break;
                }
            }
            if (isValid) {
                maxArea += pieces[i].area;
            }
        }
        printf("%d\n", maxArea);
    }
}

